import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.CMAFtOGK.js";const p=JSON.parse('{"title":"01 马克思主义中国化时代化","description":"政治理论 · 01 马克思主义中国化时代化","frontmatter":{"title":"01 马克思主义中国化时代化","description":"政治理论 · 01 马克思主义中国化时代化","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/01-马克思主义中国化时代化.md","filePath":"posts/politics/notes/01-马克思主义中国化时代化.md","lastUpdated":1784753089000}'),r={name:"posts/politics/notes/01-马克思主义中国化时代化.md"};function s(n,t,i,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="_01-马克思主义中国化时代化" tabindex="-1">01 马克思主义中国化时代化 <a class="header-anchor" href="#_01-马克思主义中国化时代化" aria-label="Permalink to &quot;01 马克思主义中国化时代化&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：把马克思主义基本原理同中国具体实际、同中华优秀传统文化相结合（<strong>两个结合</strong>）。</p></blockquote><hr><h2 id="一、核心知识" tabindex="-1">一、核心知识 <a class="header-anchor" href="#一、核心知识" aria-label="Permalink to &quot;一、核心知识&quot;">​</a></h2><h3 id="【是什么】" tabindex="-1">【是什么】 <a class="header-anchor" href="#【是什么】" aria-label="Permalink to &quot;【是什么】&quot;">​</a></h3><p><strong>马克思主义中国化时代化</strong>：把马克思主义基本原理同中国具体实际相结合、同中华优秀传统文化相结合，不断推进马克思主义中国化时代化，用马克思主义观察时代、把握时代、引领时代。</p><h3 id="【两个结合】" tabindex="-1">【两个结合】 <a class="header-anchor" href="#【两个结合】" aria-label="Permalink to &quot;【两个结合】&quot;">​</a></h3><ol><li><strong>同中国具体实际相结合</strong></li><li><strong>同中华优秀传统文化相结合</strong></li></ol><h3 id="【理论成果主线】" tabindex="-1">【理论成果主线】 <a class="header-anchor" href="#【理论成果主线】" aria-label="Permalink to &quot;【理论成果主线】&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">成果</th><th style="text-align:left;">关键词</th></tr></thead><tbody><tr><td style="text-align:left;">新民主主义革命 / 社会主义革命与建设</td><td style="text-align:left;"><strong>毛泽东思想</strong></td><td style="text-align:left;">实事求是、群众路线、独立自主</td></tr><tr><td style="text-align:left;">改革开放与现代化建设新时期</td><td style="text-align:left;"><strong>中国特色社会主义理论体系</strong></td><td style="text-align:left;">邓三科（邓 + 三 + 科）</td></tr><tr><td style="text-align:left;">中国特色社会主义新时代</td><td style="text-align:left;"><strong>习近平新时代中国特色社会主义思想</strong></td><td style="text-align:left;">两个确立、中国式现代化</td></tr></tbody></table><hr><h2 id="二、秒杀点" tabindex="-1">二、秒杀点 <a class="header-anchor" href="#二、秒杀点" aria-label="Permalink to &quot;二、秒杀点&quot;">​</a></h2><ul><li>马克思主义的<strong>理论品质</strong>：与时俱进</li><li>马克思主义中国化的<strong>精髓</strong>：实事求是</li><li>第一次历史性飞跃：<strong>毛泽东思想</strong></li><li>第二次历史性飞跃：中国特色社会主义理论体系</li><li>新时代的重大成果：<strong>习思想</strong>（当代中国马克思主义、二十一世纪马克思主义）</li></ul><hr><h2 id="三、闭卷挑战" tabindex="-1">三、闭卷挑战 <a class="header-anchor" href="#三、闭卷挑战" aria-label="Permalink to &quot;三、闭卷挑战&quot;">​</a></h2><p><strong>1.</strong> 什么是“两个结合”？</p><blockquote><p><strong>点击查看答案与解析</strong> 把马克思主义基本原理同中国具体实际相结合、同中华优秀传统文化相结合。</p></blockquote><p><strong>2.</strong> 简述马克思主义中国化时代化的历史进程与主要理论成果。</p><blockquote><p><strong>点击查看答案与解析</strong></p><ol><li>新民主主义革命和社会主义革命与建设时期 → 毛泽东思想</li><li>改革开放新时期 → 中国特色社会主义理论体系（邓小平理论、“三个代表”、科学发展观）</li><li>中国特色社会主义新时代 → 习近平新时代中国特色社会主义思想</li></ol></blockquote><p>返回：00-考试大纲与题型 · <a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a></p>',20)])])}const _=e(r,[["render",s]]);export{p as __pageData,_ as default};
